public static void main (String[] args) { 
   Oseba o1 = new Oseba("Janez", "Novak", 18); 
   o1.izpis(); 
   o1.spremeniStarost(16); 
   o1.izpis(); 
} 
// izpis programa: 
Janez Novak je star(a) 18 let. 
Janez Novak je star(a) 16 let. 
